import React, { useEffect, useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { fetchChatList } from '../redux/thunks/chatThunks';
import { fetchFriends } from '../redux/thunks/friendThunks';
import { NODE_API } from '../api/config';
import './Messages.css';

const Messages = () => {
  const [searchText, setSearchText] = useState('');
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { chatList, listLoading } = useSelector((state) => state.chat);
  const { friends } = useSelector((state) => state.friends);

  useEffect(() => {
    dispatch(fetchChatList());
    dispatch(fetchFriends({ skip: 0, limit: 50 }));
  }, [dispatch]);

  // Refresh chat list every 40 seconds (matching mobile app)
  useEffect(() => {
    const interval = setInterval(() => {
      dispatch(fetchChatList());
    }, 40000);
    return () => clearInterval(interval);
  }, [dispatch]);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const getUserFromItem = (item) => {
    // Friend list items are flat user objects
    return item || {};
  };

  // Build list from chat list + friends who haven't chatted yet
  const buildConversationList = () => {
    const chatUserIds = new Set();
    const conversations = chatList.map((item) => {
      const id = item.friendId || item._id;
      chatUserIds.add(id);
      return {
        id,
        name: item.name || 'User',
        imageURL: item.imageURL, // direct string path from .NET API
        lastMessage: item.LastMessage || '',
        count: item.count || 0,
        isOnline: item.isOnline === 1 || item.isOnline === '1',
      };
    });

    // Add friends not in chat list
    friends.forEach((f) => {
      const u = getUserFromItem(f);
      if (u?._id && !chatUserIds.has(u._id)) {
        conversations.push({
          id: u._id,
          name: u.fullName || '',
          imageURL: u.imageURL,
          lastMessage: '',
          count: 0,
          isOnline: false,
        });
      }
    });

    return conversations;
  };

  const conversations = buildConversationList();

  const filtered = searchText.trim()
    ? conversations.filter((c) => c.name.toLowerCase().includes(searchText.toLowerCase()))
    : conversations;

  return (
    <div className="messages-page">
      <div className="messages-header">
        <h1 className="messages-title">Chat</h1>
      </div>

      {/* Search */}
      <div className="messages-search">
        <input
          type="text"
          className="messages-search-input"
          placeholder="Search friends..."
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
        />
        {searchText && (
          <button className="messages-search-clear" onClick={() => setSearchText('')}>✕</button>
        )}
      </div>

      {/* Conversation list */}
      <div className="messages-list">
        {listLoading && conversations.length === 0 && (
          <div className="messages-loading"><div className="page-loading-spinner" /></div>
        )}

        {!listLoading && filtered.length === 0 && (
          <div className="messages-empty">
            <p>No conversations yet</p>
            <button className="messages-empty-btn" onClick={() => navigate('/friends')}>
              Message a friend
            </button>
          </div>
        )}

        {filtered.map((conv) => {
          const avatar = getImageUrl(typeof conv.imageURL === 'string' ? conv.imageURL : (conv.imageURL?.thumbnail || conv.imageURL));
          return (
            <div
              key={conv.id}
              className="messages-conv-card"
              onClick={() => navigate(`/chat/${conv.id}`)}
            >
              <div className="messages-conv-left">
                <div className="messages-avatar-wrap">
                  {avatar ? (
                    <img src={avatar} alt="" className="messages-avatar" />
                  ) : (
                    <div className="messages-avatar-placeholder">
                      {(conv.name[0] || 'U').toUpperCase()}
                    </div>
                  )}
                  <span className={`messages-online-dot ${conv.isOnline ? 'online' : ''}`} />
                </div>
                <div className="messages-conv-info">
                  <span className="messages-conv-name">
                    {conv.name}
                    {conv.count > 0 && <span className="messages-conv-count"> ({conv.count})</span>}
                  </span>
                  <span className="messages-conv-preview">
                    {conv.lastMessage === '#Deleted'
                      ? 'Message deleted'
                      : conv.lastMessage || 'Tap to start chatting'}
                  </span>
                </div>
              </div>
              <span className="messages-conv-arrow">→</span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Messages;
